import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { createUser, getUser, updateUser } from '../api';

export default function CreateMyCard() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: '', jobTitle: '', department: '', companyName: '', email: '', phone: '', companyUrl: '', address: ''
  });
  const [socialJson, setSocialJson] = useState('[]');
  const [files, setFiles] = useState({ companyLogo: null, profilePicture: null, coverPhoto: null });
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const scannerRef = useRef(null);
  const [scanning, setScanning] = useState(false);

  useEffect(() => {
    if (!id) return;
    setLoading(true);
    getUser(id)
      .then(u => {
        if (!u) return;
        setForm({
          name: u.name || '', jobTitle: u.jobTitle || '', department: u.department || '', companyName: u.companyName || '',
          email: u.email || '', phone: u.phone || '', companyUrl: u.companyUrl || '', address: u.address || ''
        });
        setPreview(u);
        if (u.socialLinks && Array.isArray(u.socialLinks)) setSocialJson(JSON.stringify(u.socialLinks, null, 2));
      })
      .catch(err => console.error('load failed', err))
      .finally(() => setLoading(false));
  }, [id]);

  useEffect(() => {
    // cleanup scanner on unmount
    return () => { stopScanner(); };
  }, []);

  function onChange(e){
    const { name, value } = e.target;
    setForm(f => ({ ...f, [name]: value }));
  }

  function onFileChange(e){
    const { name, files: f } = e.target;
    setFiles(prev => ({ ...prev, [name]: f && f[0] }));
  }

  async function onSave(e){
    e.preventDefault();
    setLoading(true);
    try{
      let socialStr = '';
      if (socialJson && socialJson.trim()){
        const parsed = JSON.parse(socialJson);
        if (!Array.isArray(parsed)) throw new Error('socialLinks must be a JSON array');
        socialStr = JSON.stringify(parsed);
      }

      const fd = new FormData();
      // Append only non-empty scalar fields so we don't send empty strings
      Object.entries(form).forEach(([k, v]) => {
        if (v !== null && v !== undefined && String(v).trim() !== '') {
          fd.append(k, v);
        }
      });

      // Append files only when the user selected them
      if (files.companyLogo) fd.append('companyLogo', files.companyLogo);
      if (files.profilePicture) fd.append('profilePicture', files.profilePicture);
      if (files.coverPhoto) fd.append('coverPhoto', files.coverPhoto);

      // Append social links only when present and valid
      if (socialStr) fd.append('socialLinks', socialStr);

      const saved = id ? await updateUser(id, fd) : await createUser(fd);
      setPreview(saved);
      if (saved && saved.id) navigate(`/create-my-card/${saved.id}`, { replace: true });
    }catch(err){
      console.error('save failed', err);
      const msg = err?.response?.data || err?.message || 'Unknown error';
      alert('Save failed: ' + msg);
    }finally{ setLoading(false); }
  }

  // Scanner helpers
  async function startScanner(){
    setScanning(true);
    // Lazy-load the html5-qrcode library (if installed) to avoid bundling issues
    try{
      const mod = await import('html5-qrcode');
      const { Html5Qrcode } = mod;
      const qrRegionId = 'qr-scanner-region';
      // if already initialized, stop then start fresh
      if (scannerRef.current) {
        try{ await scannerRef.current.stop(); await scannerRef.current.clear(); }catch(e){}
      }
      const html5Qr = new Html5Qrcode(qrRegionId);
      scannerRef.current = html5Qr;

      const config = { fps: 10, qrbox: { width: 250, height: 120 } };

      await html5Qr.start(
        { facingMode: 'environment' },
        config,
        (decodedText) => {
          // When a code is scanned, try to extract an ID and navigate
          handleScannedValue(decodedText);
        },
        (errorMessage) => {
          // ignore occasional scan errors
        }
      );
    }catch(err){
      console.error('Scanner start failed', err);
      // show a non-blocking console message and stop trying
      console.warn('Scanner failed to start. Ensure html5-qrcode is installed and camera permission is granted.', err);
      setScanning(false);
    }
  }

  async function stopScanner(){
    setScanning(false);
    try{
      if (scannerRef.current) {
        await scannerRef.current.stop();
        await scannerRef.current.clear();
        scannerRef.current = null;
      }
    }catch(err){
      // ignore
      console.warn('stopScanner error', err);
    }
  }

  function handleScannedValue(value){
    // Accept plain numeric ids (like "16"), or URLs that end with /create-my-card/16
    if (!value) return;
    // try URL-like patterns first
    try{
      const url = new URL(value);
      // check path segments for a numeric id
      const parts = url.pathname.split('/').filter(Boolean);
      const maybeId = parts[parts.length - 1];
      if (maybeId && /^\d+$/.test(maybeId)){
        stopScanner();
        navigate(`/create-my-card/${maybeId}`);
        return;
      }
    }catch(e){
      // not a URL — continue
    }

    // plain numeric
    const trimmed = String(value).trim();
    const digits = trimmed.match(/\d+/);
    if (digits && digits[0]){
      stopScanner();
      navigate(`/create-my-card/${digits[0]}`);
      return;
    }

    // otherwise, show a message
    alert('Scanned value did not contain a numeric id: ' + String(value).slice(0,200));
  }

  // no manual input; scanning-only mode when id exists

  // Small helper component: auto-starts the scanner when mounted and stops when unmounted
  function AutoStartScanner({ whenVisible, startScanner, stopScanner, scanning }){
    useEffect(() => {
      let mounted = true;
      if (whenVisible && mounted){
        // start immediately; ignore errors (handled by startScanner)
        startScanner();
      }
      return () => { mounted = false; stopScanner && stopScanner(); };
    }, [whenVisible]);

    return (
      <div style={{ marginTop: 6, color: scanning ? '#0a0' : '#888', fontSize: 13 }}>
        {scanning ? 'Kamera açık, barkodu tutun...' : 'Kamera kapalı veya erişim bekleniyor...'}
      </div>
    );
  }

  return (
    <div className="create-card" style={{ display: 'flex', gap: 24, padding: 24 }}>
      <div className="form-panel" style={{ flex: 1 }}>
        <h2>Create My Card</h2>
        <form onSubmit={onSave}>
          <div style={{ display: 'grid', gap: 8 }}>
            <label>Name<input name="name" value={form.name} onChange={onChange} /></label>
            <label>Job title<input name="jobTitle" value={form.jobTitle} onChange={onChange} /></label>
            <label>Department<input name="department" value={form.department} onChange={onChange} /></label>
            <label>Company<input name="companyName" value={form.companyName} onChange={onChange} /></label>
            <label>Email<input name="email" value={form.email} onChange={onChange} /></label>
            <label>Phone<input name="phone" value={form.phone} onChange={onChange} /></label>
            <label>Company URL<input name="companyUrl" value={form.companyUrl} onChange={onChange} /></label>
            <label>Address<input name="address" value={form.address} onChange={onChange} /></label>

            <label>Social links (JSON array)
              <textarea rows={6} value={socialJson} onChange={e => setSocialJson(e.target.value)} />
            </label>

            <label>Company Logo<input type="file" name="companyLogo" onChange={onFileChange} accept="image/*" /></label>
            <label>Profile Picture<input type="file" name="profilePicture" onChange={onFileChange} accept="image/*" /></label>
            <label>Cover Photo<input type="file" name="coverPhoto" onChange={onFileChange} accept="image/*" /></label>

            <div style={{ marginTop: 12 }}>
              <button type="submit" style={{ padding: '8px 16px' }} disabled={loading}>{id ? 'Update' : 'Save'}</button>
            </div>
          </div>
        </form>
      </div>

      <div className="preview-panel" style={{ width: 380 }}>
        <h3>Preview / Saved</h3>
        { (id || (preview && preview.id)) && (
          <div style={{ marginBottom: 12 }}>
            <h4 style={{ margin: '6px 0' }}>Barkod okutun</h4>
            <div id="qr-scanner-region" style={{ width: '100%', height: 220, background: '#000', borderRadius: 6 }} />
            {/* auto-start scanner when visible */}
            <AutoStartScanner whenVisible={Boolean(id || (preview && preview.id))} startScanner={startScanner} stopScanner={stopScanner} scanning={scanning} />
          </div>
        )}
        {loading && <div>Loading…</div>}
        {preview ? (
          <div className="card-preview">
            {preview.coverPhoto && <img className="cover" src={preview.coverPhoto} alt="cover" style={{ width: '100%', objectFit: 'cover', borderRadius: 6 }} />}
            <div className="profile-row" style={{ display: 'flex', gap: 12, alignItems: 'center', marginTop: 8 }}>
              {preview.profilePicture && <img className="avatar" src={preview.profilePicture} alt="profile" style={{ width: 72, height: 72, objectFit: 'cover', borderRadius: 8 }} />}
              {preview.companyLogo && <img className="avatar" src={preview.companyLogo} alt="company logo" style={{ width: 72, height: 72, objectFit: 'cover', borderRadius: 8 }} />}
              <div>
                <h4 style={{ margin: 0 }}>{preview.name}</h4>
                <div style={{ color: '#555' }}>{preview.jobTitle}</div>
                <div style={{ color: '#777', fontSize: 13 }}>{preview.companyName}</div>
              </div>
            </div>
            <div className="meta" style={{ marginTop: 8, color: '#333' }}>
              <div>{preview.email}</div>
              <div>{preview.phone}</div>
              <div>{preview.companyUrl}</div>
            </div>
            {preview.socialLinks && preview.socialLinks.length > 0 && (
              <div className="social-links" style={{ marginTop: 10 }}>
                <h5 style={{ margin: '8px 0' }}>Social</h5>
                <ul>
                  {preview.socialLinks.map((s, i) => (
                    <li key={i}>{s.platform}: {s.link}</li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        ) : (
          <div>No saved data yet. Fill the form and hit Save.</div>
        )}
      </div>
    </div>
  );
}
